"use strict";(self.webpackChunkleetcode=self.webpackChunkleetcode||[]).push([[4417],{4703:e=>{e.exports=JSON.parse('{"tag":{"label":"two-pointers","permalink":"/leetcode/pt-BR/docs/tags/two-pointers","allTagsPath":"/leetcode/pt-BR/docs/tags","count":19,"items":[{"id":"problems/three-sum","title":"3Sum","description":"Given a list of integers, nums, return a list containing all triplets that sum to zero.","permalink":"/leetcode/pt-BR/docs/problems/three-sum"},{"id":"problems/assign-cake","title":"Assign Cake","description":"This question is asked by Amazon. You are at a birthday party and are asked to distribute cake to your guests. Each guest is only satisfied if the size of the piece of cake they\'re given matches their appetite (i.e., is greater than or equal to their appetite). Given two arrays, appetite and cake where the ith element of appetite represents the ith guest\'s appetite, and the elements of cake represents the sizes of cake you have to distribute, return the maximum number of guests that you can satisfy.","permalink":"/leetcode/pt-BR/docs/problems/assign-cake"},{"id":"problems/boats-to-save-people","title":"Boats to Save People","description":"This question is asked by Amazon. A ship is about to set sail and you are responsible for its safety precautions. More specifically, you are responsible for determining how many life rafts to carry onboard. You are given a list of all the passengers\' weights and are informed that a single life raft has a maximum capacity of limit and can hold at most two people. Return the minimum number of life rafts you must take onboard to ensure the safety of all your passengers.","permalink":"/leetcode/pt-BR/docs/problems/boats-to-save-people"},{"id":"problems/container-with-most-water","title":"Container With Most Water","description":"You are building a pool in your backyard and want to create the largest pool possible. The largest pool is defined as the pool that holds the most water. The workers you hired to dig the hole for your pool didn\'t do a great job and because of this the depths of the pool at different areas are not equal. Given an integer array of non-negative integers that represents a histogram of the different heights at each position of the hole for your pool, return the largest pool you can create.","permalink":"/leetcode/pt-BR/docs/problems/container-with-most-water"},{"id":"problems/find-first-occurrence","title":"Find First Occurrence in String","description":"Given two strings s and t, return the index of the first occurrence of t within s if it exists; otherwise, return -1.","permalink":"/leetcode/pt-BR/docs/problems/find-first-occurrence"},{"id":"problems/happy-number","title":"Happy Number (Magical Number)","description":"Given an integer n, return whether or not it is a \\"magical\\" number. A magical number is an integer such that when you repeatedly replace the number with the sum of the squares of its digits, it eventually becomes one.","permalink":"/leetcode/pt-BR/docs/problems/happy-number"},{"id":"problems/is-subsequence","title":"Is Subsequence","description":"This question is asked by Google. Given two strings s and t, return whether or not s is a subsequence of t.","permalink":"/leetcode/pt-BR/docs/problems/is-subsequence"},{"id":"problems/longest-substring-two-distinct","title":"Longest Substring with At Most Two Distinct Characters","description":"Given a string s, return the length of the longest substring containing at most two distinct characters.","permalink":"/leetcode/pt-BR/docs/problems/longest-substring-two-distinct"},{"id":"problems/longest-substring-without-repeating-characters","title":"Longest Substring Without Repeating Characters","description":"Given a string s, return the length of the longest substring that contains only unique characters.","permalink":"/leetcode/pt-BR/docs/problems/longest-substring-without-repeating-characters"},{"id":"problems/move-zeroes","title":"Move Zeroes","description":"This question is asked by Apple. Given an array of numbers, move all zeroes in the array to the end while maintaining the relative order of the other numbers.","permalink":"/leetcode/pt-BR/docs/problems/move-zeroes"},{"id":"problems/palindrome-check","title":"Palindrome Check","description":"Given a string s, return true if it is a palindrome, and false otherwise. Ignore non-alphanumeric characters and case.","permalink":"/leetcode/pt-BR/docs/problems/palindrome-check"},{"id":"problems/partition-labels","title":"Partition Labels","description":"Given a string s containing only lowercase characters, return a list of integers representing the size of each substring you can create such that each character in s only appears in one substring.","permalink":"/leetcode/pt-BR/docs/problems/partition-labels"},{"id":"problems/remove-element","title":"Remove Element","description":"Given an integer array nums and a value val, remove all instances of val in-place and return the length of the new array.","permalink":"/leetcode/pt-BR/docs/problems/remove-element"},{"id":"problems/reverse-vowels","title":"Reverse Vowels of a String","description":"This question is asked by Facebook. Given a string, reverse the vowels of it.","permalink":"/leetcode/pt-BR/docs/problems/reverse-vowels"},{"id":"problems/reverse-words","title":"Reverse Words in a String","description":"Given a string s, reverse the words.","permalink":"/leetcode/pt-BR/docs/problems/reverse-words"},{"id":"problems/shortest-distance-to-character","title":"Shortest Distance to Character","description":"Given a string s and a character c, return an array of integers where each index is the shortest distance from the character at that position to the nearest occurrence of c in the string.","permalink":"/leetcode/pt-BR/docs/problems/shortest-distance-to-character"},{"id":"problems/sort-array-by-parity-ii","title":"Sort Array By Parity II","description":"This question is asked by Amazon. Given an array of integers, nums, sort the array in any manner such that when i is even, nums[i] is even and when i is odd, nums[i] is odd.","permalink":"/leetcode/pt-BR/docs/problems/sort-array-by-parity-ii"},{"id":"problems/string-compression","title":"String Compression","description":"This question is asked by Facebook. Given a character array, compress it in place and return the new length of the array.","permalink":"/leetcode/pt-BR/docs/problems/string-compression"},{"id":"problems/two-sum-bst","title":"Two Sum IV - Input is a BST","description":"Given the reference to the root of a binary search tree and a target value, return whether or not two individual values within the tree can sum to the target.","permalink":"/leetcode/pt-BR/docs/problems/two-sum-bst"}],"unlisted":false}}')}}]);